#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    long long N;
    int K;
    cin >> N >> K;

    vector<pair<long long, long long>> pairs(K);
    for (int i = 0; i < K; i++) {
        long long a, b;
        cin >> a >> b;
        if (a > b) swap(a, b);
        pairs[i] = {a, b};
    }

    // For each cow, we only care about the leftmost conflict that starts at or after this cow.
    // Actually, we process from left to right, maintaining the rightmost "left endpoint"
    // of a conflict whose right endpoint is the current position? Let's think differently.

    // Approach: For each position i (as we sweep), we want the leftmost unfriendly pair 
    // that starts at or after i. We'll track the earliest "right bound" of a pair.
    // Actually, we can think in terms of intervals: each unfriendly pair (a,b) 
    // means we cannot have both a and b in the same photo, i.e., we must cut between a and b-1 somewhere.
    // More precisely: if a photo includes cow a, it cannot include cow b, so there must be a cut 
    // in [a, b-1] (i.e., a photo boundary somewhere between a and b-1 inclusive).
    // We want minimum number of photos = minimum number of cuts + 1.
    // Each cut can satisfy multiple pairs. We need to place cuts to "hit" all intervals [a, b-1].
    // This is the classic "minimum points to hit all intervals" (greedy by right endpoint).

    vector<pair<long long, long long>> intervals;
    for (auto &p : pairs) {
        long long a = p.first, b = p.second;
        // need a cut in [a, b-1]
        intervals.push_back({b - 1, a}); // store (right, left) for sorting by right
    }

    sort(intervals.begin(), intervals.end());

    long long cuts = 0;
    long long last_cut = -1; // position of last cut (cuts are between cows)

    for (auto &inv : intervals) {
        long long r = inv.first;   // right endpoint of interval
        long long l = inv.second;  // left endpoint
        // if last cut is not inside this interval, we need a new cut
        if (last_cut < l || last_cut > r) {
            // place cut at r
            cuts++;
            last_cut = r;
        }
    }

    // number of photos = cuts + 1
    cout << cuts + 1 << "\n";

    return 0;
}
